#include <iostream>
#include <vector>

// Assume isPrime(int num) is defined externally or in the same compilation unit.
extern bool isPrime(int num);

int main() {
    std::vector<int> testNums = {2, 3, 4, 5, 6, 7, 10, 11, 13, 17, 19, 23, 1, 0, -5};
    std::cout << "Testing isPrime function:" << std::endl;
    for (int num : testNums) {
        std::cout << "isPrime(" << num << "): " << (isPrime(num) ? "true" : "false") << std::endl;
    }
    return 0;
}
